const SLOTS = {
  equip: [
    { id:"weapon",   category:"weapon",   top:4.6,  left:2.3,  right:null, w:21,   h:24   },
    { id:"helmet",   category:"helmet",   top:4.6,  left:null, right:3.1,  w:21,   h:24   },
    { id:"necklace", category:"necklace", top:36.2, left:2.2,  right:null, w:21,   h:24   },
    { id:"armor",    category:"armor",    top:36,   left:null, right:3,    w:21,   h:24   },
    { id:"ring",     category:"ring",     top:67.3, left:2.3,  right:null, w:21,   h:24   },
    { id:"boots",    category:"boots",    top:67.5, left:null, right:2.9,  w:21,   h:24   },
  ],
  runes: [
    { id:"hex1",  top:12.6, left:10.3, right:null, w:13, h:18 },
    { id:"hex2",  top:31.6, left:3,    right:null, w:13, h:18 },
    { id:"hex3",  top:53,   left:2.2,  right:null, w:13, h:18 },
    { id:"hex4",  top:71.1, left:9.9,  right:null, w:13, h:18 },
    { id:"star1", top:12.2, left:null, right:10.9, w:13, h:18 },
    { id:"star2", top:30,   left:null, right:3.4,  w:13, h:18 },
    { id:"star3", top:51.9, left:null, right:2.7,  w:13, h:18 },
    { id:"star4", top:71,   left:null, right:10.3, w:13, h:18 },
    { id:"oct1",  top:41.6, left:19.7, right:null, w:12, h:17 },
    { id:"oct2",  top:41.8, left:null, right:19.7, w:12, h:17 },
    { id:"dia1",  top:69.3, left:27.7, right:null, w:12, h:18 },
    { id:"dia2",  top:69.3, left:43.9, right:null, w:12, h:18 },
    { id:"dia3",  top:69.2, left:null, right:28.3, w:12, h:18 },
  ],
  chars: [
    { id:"deployed",  top:23.5, left:4.7,  right:null, w:20.5, h:44   },
    { id:"res1",      top:23.5, left:28,   right:null, w:20.5, h:44   },
    { id:"res2",      top:23.6, left:51.4, right:null, w:20.5, h:44   },
    { id:"mystling",  top:25.1, left:76.2, right:null, w:17.5, h:42.5, shape:"oval" },
    { id:"dep-sub1",  top:68.2, left:4.1,  right:null, w:11,   h:22   },
    { id:"dep-sub2",  top:68.4, left:14.7, right:null, w:11,   h:22   },
    { id:"res1-sub1", top:68.5, left:27.5, right:null, w:11,   h:22   },
    { id:"res1-sub2", top:68.6, left:38,   right:null, w:11,   h:22   },
    { id:"res2-sub1", top:68.1, left:50.9, right:null, w:11,   h:22   },
    { id:"res2-sub2", top:68,   left:61,   right:null, w:11,   h:22   },
  ],
};

// ── Item Picker Modal ──
function ItemPicker({ category, onSelect, onClose, onClear, current }) {
  const items = ITEMS[category] || [];
  return (
    <div
      onClick={onClose}
      style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.75)", zIndex:200,
        display:"flex", alignItems:"flex-end", justifyContent:"center" }}
    >
      <div
        onClick={e => e.stopPropagation()}
        style={{ background:"#1a1635", borderRadius:"20px 20px 0 0", padding:"20px 16px 36px",
          width:"100%", maxWidth:700, border:"2px solid #4a3d7a",
          boxShadow:"0 -8px 32px rgba(0,0,0,0.6)" }}
      >
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <span style={{ color:"#FFD966", fontWeight:800, fontSize:17, textTransform:"capitalize" }}>
            Select {category}
          </span>
          <button onClick={onClose}
            style={{ background:"#2a2a4a", border:"none", color:"#a0a8d0", borderRadius:50,
              padding:"6px 16px", fontWeight:800, fontSize:14, cursor:"pointer" }}>
            ✕
          </button>
        </div>

        {items.length === 0 ? (
          <p style={{ color:"#a0a8c0", textAlign:"center", padding:"24px 0", fontSize:14 }}>
            No items yet for this slot
          </p>
        ) : (
          <div style={{ display:"flex", flexWrap:"wrap", gap:12, justifyContent:"center" }}>
            {items.map(item => (
              <div key={item.id} onClick={() => onSelect(item)}
                style={{ width:90, cursor:"pointer", display:"flex", flexDirection:"column",
                  alignItems:"center", gap:6,
                  border: current === item.id ? "2.5px solid #FFD966" : "2px solid transparent",
                  borderRadius:14, padding:6,
                  background: current === item.id ? "rgba(255,215,80,0.12)" : "rgba(255,255,255,0.04)",
                  transition:"all 0.15s" }}
              >
                <img src={item.img} style={{ width:72, height:72, objectFit:"contain", borderRadius:10 }} />
                <span style={{ fontSize:11, color:"#c9aaff", fontWeight:700, textAlign:"center", lineHeight:1.2 }}>
                  {item.name}
                </span>
              </div>
            ))}
          </div>
        )}

        {current && (
          <button onClick={onClear}
            style={{ marginTop:18, width:"100%", padding:"12px", borderRadius:50, border:"none",
              cursor:"pointer", fontWeight:800, fontSize:14,
              background:"#2d1a1a", color:"#f87171", boxShadow:"0 2px 0 #7a1a1a" }}>
            🗑 Remove item
          </button>
        )}
      </div>
    </div>
  );
}

// ── Single Slot ──
function Slot({ slot, filled, onTap, onLongPress, sizeOverride, posOverride }) {
  const br = slot.shape === "oval" ? "50%" : "10px";
  const item = filled ? (ITEMS[slot.category] || []).find(i => i.id === filled) : null;
  const timer = useRef(null);
  const sz = sizeOverride ?? slot.w;
  const ratio = sz / slot.w;
  const top   = posOverride?.top   ?? slot.top;
  const left  = posOverride?.left  ?? slot.left;
  const right = posOverride?.right ?? slot.right;

  const handleTouchStart = () => {
    // Always start timer; long press only triggers resize when slot is filled
    timer.current = setTimeout(() => {
      timer.current = null;
      if (item) onLongPress(slot);
    }, 1000);
  };
  const handleTouchEnd = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (timer.current) {
      // Timer still running = short tap
      clearTimeout(timer.current);
      timer.current = null;
      onTap(slot);
    }
    // If timer already fired = long press, do nothing here
  };
  const handleTouchMove = () => {
    if (timer.current) { clearTimeout(timer.current); timer.current = null; }
  };

  return (
    <div
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
      onTouchMove={handleTouchMove}
      onClick={() => onTap(slot)}
      style={{
        position:"absolute",
        top: top + "%",
        width: sz + "%",
        height: (slot.h * ratio) + "%",
        ...(left !== null ? { left: left + "%" } : { right: right + "%" }),
        borderRadius: br,
        border: item ? "none" : "2px dashed rgba(255,215,80,0.35)",
        background: item ? "transparent" : "rgba(255,215,80,0.05)",
        boxSizing:"border-box",
        cursor:"pointer",
        zIndex:10,
        overflow:"hidden",
        touchAction:"manipulation",
        transition:"border 0.15s",
        display:"flex", alignItems:"center", justifyContent:"center",
      }}
    >
      {item ? (
        <img src={item.img}
          style={{ width:"100%", height:"100%", objectFit:"cover", borderRadius: br }} />
      ) : (
        <span style={{ fontSize:18, color:"rgba(255,215,80,0.45)", pointerEvents:"none" }}>+</span>
      )}
    </div>
  );
}

export default function Archero2Builder() {
  const [filled, setFilled]     = useState({});   // slotId -> itemId
  const [picker, setPicker]     = useState(null);  // { slotId, category }
  const [sizePanel, setSizePanel] = useState(null); // slotId being resized
  const [sizes, setSizes]       = useState({"w1": 25.5, "w2": 25.5, "w3": 25.5, "am1": 25.5, "am2": 25.5, "am3": 25.5, "rn1": 25.5, "rn2": 25.5, "rn3": 25.5, "hm1": 26, "hm2": 25.5, "hm3": 25.5, "ar1": 25.5, "ar2": 25.5, "ar3": 25.5, "bt1": 25.5, "bt2": 25.5, "bt3": 25.5});
  const [positions, setPositions] = useState({"w1": {"top": 2.1, "left": 0.3, "right": null}, "w2": {"top": 2.1, "left": 0.3, "right": null}, "w3": {"top": 2.6, "left": 0.3, "right": null}, "am1": {"top": 34.2, "left": 0.7, "right": null}, "am2": {"top": 34.2, "left": 0.7, "right": null}, "am3": {"top": 34.7, "left": 0.7, "right": null}, "rn1": {"top": 65.8, "left": 0.8, "right": null}, "rn2": {"top": 66.3, "left": 0.8, "right": null}, "rn3": {"top": 66.8, "left": 0.8, "right": null}, "hm1": {"top": 2.6, "left": null, "right": 0.1}, "hm2": {"top": 3.6, "left": null, "right": 0.6}, "hm3": {"top": 3.6, "left": null, "right": 0.6}, "ar1": {"top": 34.5, "left": null, "right": 0.5}, "ar2": {"top": 34.5, "left": null, "right": 0.5}, "ar3": {"top": 34.5, "left": null, "right": 0.5}, "bt1": {"top": 66.5, "left": null, "right": 0.4}, "bt2": {"top": 66.0, "left": null, "right": 0.4}, "bt3": {"top": 66.0, "left": null, "right": 0.4}});

  const handleTap = (slot) => {
    if (!slot.category) return;
    setPicker({ slotId: slot.id, category: slot.category });
  };

  const handleLongPress = (slot) => {
    const itemId = filled[slot.id];
    if (!itemId) return;
    setSizePanel({ slotId: slot.id, itemId });
  };

  const handleSelect = (item) => {
    setFilled(prev => ({ ...prev, [picker.slotId]: item.id }));
    setPicker(null);
  };

  const handleClear = () => {
    setFilled(prev => { const n = {...prev}; delete n[picker.slotId]; return n; });
    setPicker(null);
  };

  // find slot object for size panel
  const sizePanelSlot = sizePanel
    ? Object.values(SLOTS).flat().find(s => s.id === sizePanel.slotId)
    : null;
  const currentItemId = sizePanel?.itemId ?? null;
  const currentSize = currentItemId
    ? (sizes[currentItemId] ?? sizePanelSlot?.w ?? 20)
    : 20;

  const btnStyle = { background:"#2a2a5a", border:"2px solid #5a4a9a", color:"#c9aaff",
    borderRadius:10, width:48, height:48, fontSize:20, fontWeight:800,
    cursor:"pointer", touchAction:"manipulation" };

  const nudge = (axis, delta) => {
    if (!sizePanelSlot || !currentItemId) return;
    setPositions(prev => {
      const base = prev[currentItemId] ?? {
        top: sizePanelSlot.top,
        left: sizePanelSlot.left,
        right: sizePanelSlot.right,
      };
      if (axis === "top")  return { ...prev, [currentItemId]: { ...base, top: Math.round((base.top + delta) * 10) / 10 }};
      if (axis === "left"  && base.left  !== null) return { ...prev, [currentItemId]: { ...base, left:  Math.round((base.left  + delta) * 10) / 10 }};
      if (axis === "right" && base.right !== null) return { ...prev, [currentItemId]: { ...base, right: Math.round((base.right - delta) * 10) / 10 }};
      return prev;
    });
  };

  return (
    <div style={{ fontFamily:"sans-serif", background:"#111122", minHeight:"100vh",
      padding:"16px 12px 40px", display:"flex", flexDirection:"column", alignItems:"center" }}>

      <h1 style={{ fontWeight:900, fontSize:22, color:"#FFD966", textAlign:"center",
        marginBottom:4, textShadow:"0 2px 0 #7a5800" }}>
        ⚔️ Archero 2 — Build Constructor
      </h1>
      <p style={{ color:"#a0a8c0", fontSize:13, marginBottom:20, textAlign:"center" }}>
        Tap any slot to select an item
      </p>

      <div id="builder-export" style={{ width:"100%", maxWidth:700, display:"flex",
        flexDirection:"column", gap:14, background:"#111122", padding:14, borderRadius:20 }}>
        {["equip","runes","chars"].map(sec => (
          <div key={sec} style={{ borderRadius:16, overflow:"hidden", position:"relative" }}>
            <img
              src={sec==="equip" ? EQUIP_IMG : sec==="runes" ? RUNES_IMG : CHARS_IMG}
              style={{ width:"100%", display:"block", pointerEvents:"none" }}
              alt={sec}
            />
            {SLOTS[sec].map(slot => (
              <Slot key={slot.id} slot={slot}
                filled={filled[slot.id]}
                onTap={handleTap}
                onLongPress={handleLongPress}
                sizeOverride={sizes[filled[slot.id]] ?? null}
                posOverride={positions[filled[slot.id]] ?? null} />
            ))}
          </div>
        ))}
      </div>

      {/* ── SIZE PANEL ── */}
      {sizePanel && sizePanelSlot && (
        <div style={{ position:"fixed", bottom:0, left:0, right:0, background:"#1a1635",
          border:"2px solid #60a5fa", borderRadius:"20px 20px 0 0",
          padding:"20px 20px 36px", zIndex:300, boxShadow:"0 -8px 32px rgba(0,0,0,0.6)" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
            <span style={{ color:"#60a5fa", fontWeight:800, fontSize:16 }}>
              📐 {sizePanel?.itemId}
            </span>
            <div style={{display:"flex", gap:8}}>
              <button onClick={() => {
                const text = JSON.stringify({ sizes, positions }, null, 2);
                const ta = document.createElement("textarea");
                ta.value = text; ta.style.position="fixed"; ta.style.opacity="0";
                document.body.appendChild(ta); ta.focus(); ta.select();
                try { document.execCommand("copy"); } catch(e) {}
                document.body.removeChild(ta);
                if (navigator.clipboard?.writeText) navigator.clipboard.writeText(text).catch(()=>{});
                alert("Sizes copied! Paste to chat.");
              }}
                style={{ background:"#3a2d6a", border:"none", color:"#c9aaff",
                  borderRadius:50, padding:"6px 16px", fontWeight:800, fontSize:14, cursor:"pointer" }}>
                📋 Copy
              </button>
              <button onClick={() => setSizePanel(null)}
                style={{ background:"#2a2a4a", border:"none", color:"#a0a8d0",
                  borderRadius:50, padding:"6px 16px", fontWeight:800, fontSize:14, cursor:"pointer" }}>
                ✕ Done
              </button>
            </div>
          </div>
          <label style={{ color:"#c9aaff", fontSize:14, display:"block", marginBottom:8 }}>
            Size: <strong style={{color:"#fff"}}>{currentSize.toFixed(1)}%</strong>
          </label>
          <input type="range" min="5" max="50" step="0.5"
            value={currentSize}
            onChange={e => setSizes(prev => ({ ...prev, [currentItemId]: parseFloat(e.target.value) }))}
            style={{ width:"100%", height:28, marginBottom:16 }} />

          <label style={{ color:"#c9aaff", fontSize:14, display:"block", marginBottom:10 }}>
            Position
          </label>
          <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:6 }}>
            <button onTouchEnd={e=>{e.preventDefault();nudge("top",-0.5);}} onClick={()=>nudge("top",-0.5)}
              style={btnStyle}>▲</button>
            <div style={{ display:"flex", gap:24 }}>
              <button onTouchEnd={e=>{e.preventDefault(); sizePanelSlot?.left!==null?nudge("left",-0.5):nudge("right",0.5);}} onClick={()=>sizePanelSlot?.left!==null?nudge("left",-0.5):nudge("right",0.5)}
                style={btnStyle}>◀</button>
              <button onTouchEnd={e=>{e.preventDefault(); sizePanelSlot?.left!==null?nudge("left",0.5):nudge("right",-0.5);}} onClick={()=>sizePanelSlot?.left!==null?nudge("left",0.5):nudge("right",-0.5)}
                style={btnStyle}>▶</button>
            </div>
            <button onTouchEnd={e=>{e.preventDefault();nudge("top",0.5);}} onClick={()=>nudge("top",0.5)}
              style={btnStyle}>▼</button>
          </div>
        </div>
      )}

      <button
        onClick={async () => {
          const el = document.getElementById("builder-export");
          if (!window.html2canvas) {
            const sc = document.createElement("script");
            sc.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
            document.head.appendChild(sc);
            await new Promise(r => sc.onload = r);
          }
          const canvas = await window.html2canvas(el, { scale:2, backgroundColor:"#111122", useCORS:true });
          const a = document.createElement("a");
          a.download = "archero2-build.png";
          a.href = canvas.toDataURL("image/png");
          a.click();
        }}
        style={{ marginTop:20, padding:"13px 36px", borderRadius:50, border:"none",
          cursor:"pointer", fontWeight:800, fontSize:15,
          background:"linear-gradient(180deg,#FFE066,#FFC107)", color:"#7a4f00",
          boxShadow:"0 3px 0 #a06800" }}>
        ⬇ Export PNG
      </button>

      {picker && (
        <ItemPicker
          category={picker.category}
          current={filled[picker.slotId]}
          onSelect={handleSelect}
          onClose={() => setPicker(null)}
          onClear={handleClear}
        />
      )}
    </div>
  );
}
